// Auto-generated by r2factor. Manual edits will be overwritten on next split.

use ndarray::Array1;
use std::error::Error;

/// Parse an angle string from trace names (e.g., "-60°", "0° (ON)", "10°")
///
/// # Arguments
/// * `name` - The trace name containing an angle
///
/// # Returns
/// * Some(angle) if the angle could be parsed, None otherwise
pub(super) fn parse_angle_from_trace_name(name: &str) -> Option<f64> {
    let normalized = name.replace('\u{2212}', "-").replace('°', " ");

    if normalized.trim().eq_ignore_ascii_case("ON") {
        return Some(0.0);
    }

    normalized
        .split(|c: char| c.is_whitespace() || c == '(' || c == ')' || c == ',' || c == ':')
        .find_map(|token| token.parse::<f64>().ok())
}

/// Parse headphone frequency response CSV from the spinorama API.
///
/// Format: 4-column CSV with multiple header rows:
/// ```text
/// "Frequency Response Reference 425 Hz @ 94 dBSPL",,,
/// "Left (94 dB)",,Right,
/// X,Y,X,Y
/// Hz,dBSPL,Hz,dBSPL
/// 19.23,104.00,19.23,102.33
/// ...
/// ```
/// Non-numeric rows are automatically skipped. L/R channels are averaged.
pub(super) fn parse_headphone_csv(csv_text: &str) -> Result<crate::Curve, Box<dyn Error>> {
    let mut frequencies = Vec::new();
    let mut spl_values = Vec::new();

    for line in csv_text.lines() {
        let line = line.trim().trim_matches('"');
        if line.is_empty() {
            continue;
        }

        let parts: Vec<&str> = line
            .split(',')
            .map(|s| s.trim().trim_matches('"'))
            .collect();

        if parts.len() >= 4 {
            // 4-column: freq_L, spl_L, freq_R, spl_R → average L/R
            if let (Ok(freq_l), Ok(spl_l), Ok(_freq_r), Ok(spl_r)) = (
                parts[0].parse::<f64>(),
                parts[1].parse::<f64>(),
                parts[2].parse::<f64>(),
                parts[3].parse::<f64>(),
            ) {
                frequencies.push(freq_l);
                spl_values.push((spl_l + spl_r) / 2.0);
            }
        } else if parts.len() >= 2 {
            // 2-column: freq, spl
            if let (Ok(freq), Ok(spl)) = (parts[0].parse::<f64>(), parts[1].parse::<f64>()) {
                frequencies.push(freq);
                spl_values.push(spl);
            }
        }
    }

    if frequencies.is_empty() {
        return Err("No valid frequency response data found in CSV".into());
    }

    Ok(crate::Curve {
        freq: Array1::from(frequencies),
        spl: Array1::from(spl_values),
        phase: None,
        ..Default::default()
    })
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_angle_from_trace_name_accepts_spinorama_directivity_labels() {
        assert_eq!(parse_angle_from_trace_name("-60°"), Some(-60.0));
        assert_eq!(parse_angle_from_trace_name("−60°"), Some(-60.0));
        assert_eq!(parse_angle_from_trace_name("0° (ON)"), Some(0.0));
        assert_eq!(parse_angle_from_trace_name("ON"), Some(0.0));
        assert_eq!(parse_angle_from_trace_name("10°"), Some(10.0));
    }

    #[test]
    fn parse_headphone_csv_averages_left_right() {
        let csv = r#""Frequency Response",,,
"Left",,Right,
X,Y,X,Y
Hz,dBSPL,Hz,dBSPL
20,100,20,104
100,90,100,92
"#;
        let curve = parse_headphone_csv(csv).unwrap();
        assert_eq!(curve.freq.len(), 2);
        assert!((curve.spl[0] - 102.0).abs() < 1e-9);
        assert!((curve.spl[1] - 91.0).abs() < 1e-9);
    }

    #[test]
    fn parse_headphone_csv_two_column() {
        let csv = "freq,spl\n20,100\n100,90\n";
        let curve = parse_headphone_csv(csv).unwrap();
        assert_eq!(curve.freq.len(), 2);
        assert!((curve.spl[1] - 90.0).abs() < 1e-9);
    }

    #[test]
    fn parse_headphone_csv_no_data_errors() {
        let csv = "header,header\n";
        assert!(parse_headphone_csv(csv).is_err());
    }
}
